async function loadPlaceholder(){try{const e=document.getElementById("event-placeholder"),t=e.dataset.event,n=e.dataset.eventId,a=populateEventDates(n);if(0===a.length){const n=await fetch("/assets/components/placeholder.html"),a=await n.text();e.innerHTML=a,document.getElementById("placeholder-event").innerText=t}}catch(e){console.error("Error loading placeholder:",e)}}document.addEventListener("DOMContentLoaded",loadPlaceholder);